import React, { useState } from "react";
import Login from "./Login";
import Admin from "./Admin";
import User from "./User";

function App() {
  const [role, setRole] = useState(null);

  if (!role) return <Login setRole={setRole} />;
  if (role === "admin") return <Admin />;
  return <User />;
}

export default App;
